func TestTargetPort(t *testing.T) {
	tp := TargetPort{
		PathPrefix: "/api",
		Name:       "http",
		Port:       8080,
		Protocol:   ProtocolHTTP,
	}

	data, err := json.Marshal(tp)
	if err != nil {
		t.Fatalf("json.Marshal() error = %v", err)
	}

	var tp2 TargetPort
	if err := json.Unmarshal(data, &tp2); err != nil {
		t.Fatalf("json.Unmarshal() error = %v", err)
	}

	if tp2.PathPrefix != tp.PathPrefix || tp2.Name != tp.Name ||
		tp2.Port != tp.Port || tp2.Protocol != tp.Protocol {
		t.Error("TargetPort marshal/unmarshal mismatch")
	}
}

func TestTargetPortDefaults(t *testing.T) {
	tp := TargetPort{
		Port: 8080,
	}

	data, err := json.Marshal(tp)
	if err != nil {
		t.Fatalf("json.Marshal() error = %v", err)
	}

	var tp2 TargetPort
	if err := json.Unmarshal(data, &tp2); err != nil {
		t.Fatalf("json.Unmarshal() error = %v", err)
	}

	if tp2.Port != tp.Port {
		t.Error("TargetPort default marshal/unmarshal mismatch")
	}
}

