func TestConstants(t *testing.T) {
	tests := []struct {
		name     string
		value    time.Duration
		expected time.Duration
	}{
		{"DefaultSandboxTTL", DefaultSandboxTTL, 8 * time.Hour},
		{"DefaultSandboxIdleTimeout", DefaultSandboxIdleTimeout, 15 * time.Minute},
		{"DefaultSessionTimeout", DefaultSessionTimeout, 15 * time.Minute},
		{"SandboxCreationTimeout", SandboxCreationTimeout, 2 * time.Minute},
		{"SandboxDeleteTimeout", SandboxDeleteTimeout, 30 * time.Second},
		{"GCTickInterval", GCTickInterval, 15 * time.Second},
		{"HTTPReadTimeout", HTTPReadTimeout, 15 * time.Second},
		{"HTTPIdleTimeout", HTTPIdleTimeout, 90 * time.Second},
		{"HTTPShutdownTimeout", HTTPShutdownTimeout, 15 * time.Second},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if tt.value != tt.expected {
				t.Errorf("%s = %v, want %v", tt.name, tt.value, tt.expected)
			}
