package picod

import (
	"os"
	"testing"
)

func TestParseFlags(t *testing.T) {
	oldArgs := os.Args
	defer func() { os.Args = oldArgs }()

	os.Args = []string{"cmd", "-port", "9090", "-workspace", "/test/workspace"}
	config := ParseFlags()

	if config.Port != 9090 {
		t.Errorf("ParseFlags() Port = %d, want %d", config.Port, 9090)
	}
	if config.Workspace != "/test/workspace" {
		t.Errorf("ParseFlags() Workspace = %s, want %s", config.Workspace, "/test/workspace")
	}
}

func TestParseFlagsDefaultPort(t *testing.T) {
	oldArgs := os.Args
	defer func() { os.Args = oldArgs }()

	os.Args = []string{"cmd"}
	config := ParseFlags()

	if config.Port != 8080 {
		t.Errorf("ParseFlags() Port = %d, want %d", config.Port, 8080)
	}
}

func TestParseFlagsDefaultWorkspace(t *testing.T) {
	oldArgs := os.Args
	defer func() { os.Args = oldArgs }()

	os.Args = []string{"cmd"}
	config := ParseFlags()

	wd, _ := os.Getwd()
	if config.Workspace != wd {
		t.Errorf("ParseFlags() Workspace = %s, want %s", config.Workspace, wd)
	}
}

