)

func TestEntryPoint(t *testing.T) {
	ep := EntryPoint{
		Path:     "/api",
		Protocol: "HTTP",
		Endpoint: "localhost:8080",
	}

	data, err := json.Marshal(ep)
	if err != nil {
		t.Fatalf("json.Marshal() error = %v", err)
	}

	var ep2 EntryPoint
	if err := json.Unmarshal(data, &ep2); err != nil {
		t.Fatalf("json.Unmarshal() error = %v", err)
	}

	if ep2.Path != ep.Path || ep2.Protocol != ep.Protocol || ep2.Endpoint != ep.Endpoint {
		t.Error("EntryPoint marshal/unmarshal mismatch")
	}
}

func TestSandboxInfoValidate(t *testing.T) {
	now := time.Now()
	tests := []struct {
		name    string
		info    SandboxInfo
		wantErr bool
	}{
		{
			name: "Valid SandboxInfo",
			info: SandboxInfo{
				SessionID:  "session-1",
				SandboxID:  "sandbox-1",
				Name:       "test-sandbox",
				Namespace:  "default",
				Kind:       SandboxKind,
				ExpiresAt:  now.Add(time.Hour),
				CreatedAt:  now,
				LastActivity: now,
			},
			wantErr: false,
		},
		{
			name: "Missing SessionID",
			info: SandboxInfo{
				SandboxID: "sandbox-1",
				Name:      "test-sandbox",
				Namespace: "default",
				Kind:      SandboxKind,
				ExpiresAt: now.Add(time.Hour),
				CreatedAt: now,
			},
			wantErr: true,
		},
		{
			name: "Missing SandboxID",
			info: SandboxInfo{
				SessionID: "session-1",
				Name:      "test-sandbox",
				Namespace: "default",
				Kind:      SandboxKind,
				ExpiresAt: now.Add(time.Hour),
				CreatedAt: now,
			},
			wantErr: true,
		},
		{
			name: "Missing Name",
			info: SandboxInfo{
				SessionID: "session-1",
				SandboxID: "sandbox-1",
				Namespace: "default",
				Kind:      SandboxKind,
				ExpiresAt: now.Add(time.Hour),
				CreatedAt: now,
			},
			wantErr: true,
		},
		{
			name: "Missing Namespace",
			info: SandboxInfo{
				SessionID: "session-1",
				SandboxID: "sandbox-1",
				Name:      "test-sandbox",
				Kind:      SandboxKind,
				ExpiresAt: now.Add(time.Hour),
				CreatedAt: now,
			},
			wantErr: true,
		},
		{
			name: "Missing Kind",
			info: SandboxInfo{
				SessionID: "session-1",
				SandboxID: "sandbox-1",
				Name:      "test-sandbox",
				Namespace: "default",
				ExpiresAt: now.Add(time.Hour),
				CreatedAt: now,
			},
			wantErr: true,
		},
		{
			name: "Missing ExpiresAt",
			info: SandboxInfo{
				SessionID: "session-1",
				SandboxID: "sandbox-1",
				Name:      "test-sandbox",
				Namespace: "default",
				Kind:      SandboxKind,
				CreatedAt: now,
			},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.info.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("SandboxInfo.Validate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestCreateSandboxRequestValidate(t *testing.T) {
	tests := []struct {
		name    string
		req     CreateSandboxRequest
		wantErr bool
	}{
		{
			name: "Valid AgentRuntime request",
			req: CreateSandboxRequest{
				Kind:      AgentRuntimeKind,
				Name:      "test-runtime",
				Namespace: "default",
			},
			wantErr: false,
		},
		{
			name: "Valid CodeInterpreter request",
			req: CreateSandboxRequest{
				Kind:      CodeInterpreterKind,
				Name:      "test-interpreter",
				Namespace: "default",
			},
			wantErr: false,
		},
		{
			name: "Invalid kind",
			req: CreateSandboxRequest{
				Kind:      "InvalidKind",
				Name:      "test",
				Namespace: "default",
			},
			wantErr: true,
		},
		{
			name: "Missing namespace",
			req: CreateSandboxRequest{
				Kind: AgentRuntimeKind,
				Name: "test",
			},
			wantErr: true,
		},
		{
			name: "Missing name",
			req: CreateSandboxRequest{
				Kind:      AgentRuntimeKind,
				Namespace: "default",
			},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.req.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("CreateSandboxRequest.Validate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestCreateSandboxResponseValidate(t *testing.T) {
	tests := []struct {
