func TestSandboxInfoMarshalUnmarshal(t *testing.T) {
	now := time.Now()
	info := SandboxInfo{
		SessionID:    "session-1",
		SandboxID:    "sandbox-1",
		Name:         "test-sandbox",
		Namespace:    "default",
		Kind:         SandboxKind,
		PodIP:        "10.0.0.1",
		ExpiresAt:    now.Add(time.Hour),
		CreatedAt:    now,
		LastActivity: now,
		EntryPoints:  []EntryPoint{{Path: "/api", Protocol: "HTTP", Endpoint: "localhost:8080"}},
	}

	data, err := json.Marshal(info)
	if err != nil {
		t.Fatalf("json.Marshal() error = %v", err)
	}

	var info2 SandboxInfo
	if err := json.Unmarshal(data, &info2); err != nil {
		t.Fatalf("json.Unmarshal() error = %v", err)
	}

	if info2.SessionID != info.SessionID || info2.SandboxID != info.SandboxID ||
		info2.Name != info.Name || info2.Namespace != info.Namespace {
		t.Error("SandboxInfo marshal/unmarshal mismatch")
	}
}

