package store

import (
	"os"
	"testing"
)

func TestStorage(t *testing.T) {
	os.Setenv("STORE_TYPE", StoreTypeRedis)
	store := Storage()
	if store == nil {
		t.Fatal("Storage() returned nil")
	}
}

func TestInitStore(t *testing.T) {
	tests := []struct {
		name       string
		storeType  string
		wantErr    bool
		errMessage string
	}{
		{
			name:      "Redis store",
			storeType: StoreTypeRedis,
			wantErr:   false,
		},
		{
			name:      "Valkey store",
			storeType: StoreTypeValkey,
			wantErr:   false,
		},
		{
			name:       "Invalid store type",
			storeType:  "invalid",
			wantErr:    true,
			errMessage: "not found",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			os.Setenv("STORE_TYPE", tt.storeType)
			store, err := initStore()
			if (err != nil) != tt.wantErr {
				t.Errorf("initStore() error = %v, wantErr %v", err, tt.wantErr)
				return
			}
			if tt.wantErr && err != nil && tt.errMessage != "" {
				if gotErr := err.Error(); gotErr == "" || gotErr == "not found" {
				}
			}
			if !tt.wantErr && store == nil {
				t.Error("initStore() returned nil store")
			}
		})
	}
}

func TestInitStoreDefault(t *testing.T) {
	os.Unsetenv("STORE_TYPE")
	store, err := initStore()
	if err != nil {
		t.Errorf("initStore() error = %v, want nil", err)
	}
	if store == nil {
		t.Error("initStore() returned nil store")
	}
}

