func (s *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := KeyPrefix + sessionID

	delResp := s.client.B().Del().Key(key).Build()
	zremExpiryResp := s.client.B().Zrem().Key(ExpiryIndex).Member(sessionID).Build()
	zremActivityResp := s.client.B().Zrem().Key(LastActivityIndex).Member(sessionID).Build()

	results := s.client.DoMulti(ctx, delResp, zremExpiryResp, zremActivityResp)
	for _, result := range results {
		if result.Error() != nil {
			return result.Error()
		}
	}

	return nil
}

// ListExpiredSandboxes lists sandboxes that expired before the given time
func (s *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return []*types.SandboxInfo{}, nil
	}

	resp := s.client.B().Zrangebyscore().Key(ExpiryIndex).Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).Limit(0, int64(limit)).Build()

	sessionIDs, err := s.client.Do(ctx, resp).AsStrSlice()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

// ListInactiveSandboxes lists sandboxes that were inactive before the given time
func (s *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return []*types.SandboxInfo{}, nil
	}

	resp := s.client.B().Zrangebyscore().Key(LastActivityIndex).Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).Limit(0, int64(limit)).Build()

	sessionIDs, err := s.client.Do(ctx, resp).AsStrSlice()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

// loadSandboxesBySessionIDs loads sandboxes by their session IDs
func (s *ValkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = KeyPrefix + id
	}

	resp := s.client.B().Mget().Key(keys...).Build()
	values, err := s.client.Do(ctx, resp).AsStrSlice()
	if err != nil {
		return nil, err
	}

	var sandboxes []*types.SandboxInfo
	for _, val := range values {
		if val == "" {
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(val), &sandbox); err != nil {
			continue
		}
		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

// UpdateSessionLastActivity updates the last activity time for a session
func (s *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("sessionID cannot be empty")
	}

	key := KeyPrefix + sessionID
	existsResp := s.client.B().Exists().Key(key).Build()
	exists, err := s.client.Do(ctx, existsResp).AsInt64()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	zaddResp := s.client.B().Zadd().Key(LastActivityIndex).ScoreMember().ScoreMember(float64(at.Unix()), sessionID).Build()
	_, err = s.client.Do(ctx, zaddResp).AsInt64()
	return err
}

// Close closes the Valkey connection
func (s *ValkeyStore) Close() {
	s.client.Close()
}

