func TestRedisStoreStoreAndGetSandbox(t *testing.T) {
	mr, store, ctx := setupRedisTest(t)
	defer mr.Close()

	now := time.Now()
	sandbox := &types.SandboxInfo{
		SessionID: "test-session",
		SandboxID: "test-sandbox",
		Name:      "test-name",
		Namespace: "test-namespace",
		Kind:      types.SandboxKind,
		ExpiresAt: now.Add(time.Hour),
		CreatedAt: now,
	}

	err := store.StoreSandbox(ctx, sandbox)
	if err != nil {
		t.Fatalf("StoreSandbox failed: %v", err)
	}

	retrieved, err := store.GetSandboxBySessionID(ctx, "test-session")
	if err != nil {
		t.Fatalf("GetSandboxBySessionID failed: %v", err)
	}

	if retrieved.SessionID != sandbox.SessionID {
		t.Errorf("SessionID mismatch: got %s, want %s", retrieved.SessionID, sandbox.SessionID)
	}
	if retrieved.SandboxID != sandbox.SandboxID {
		t.Errorf("SandboxID mismatch: got %s, want %s", retrieved.SandboxID, sandbox.SandboxID)
	}
}

