func TestRedisStoreListInactiveSandboxes(t *testing.T) {
	mr, store, ctx := setupRedisTest(t)
	defer mr.Close()

	now := time.Now()

	inactiveSandbox := &types.SandboxInfo{
		SessionID: "inactive-session",
		SandboxID: "inactive-sandbox",
		Name:      "inactive-name",
		Namespace: "test-namespace",
		Kind:      types.SandboxKind,
		ExpiresAt: now.Add(time.Hour),
		CreatedAt: now.Add(-2 * time.Hour),
	}

	activeSandbox := &types.SandboxInfo{
		SessionID: "active-session",
		SandboxID: "active-sandbox",
		Name:      "active-name",
		Namespace: "test-namespace",
		Kind:      types.SandboxKind,
		ExpiresAt: now.Add(time.Hour),
		CreatedAt: now,
	}

	err := store.StoreSandbox(ctx, inactiveSandbox)
	if err != nil {
		t.Fatalf("StoreSandbox inactive failed: %v", err)
	}

	err = store.StoreSandbox(ctx, activeSandbox)
	if err != nil {
		t.Fatalf("StoreSandbox active failed: %v", err)
	}

	inactiveTime := now.Add(-2 * time.Minute)
	err = store.UpdateSessionLastActivity(ctx, "inactive-session", inactiveTime)
	if err != nil {
		t.Fatalf("UpdateSessionLastActivity failed: %v", err)
	}

	queryTime := now.Add(-time.Minute)
	inactive, err := store.ListInactiveSandboxes(ctx, queryTime, 10)
	if err != nil {
		t.Fatalf("ListInactiveSandboxes failed: %v", err)
	}

	if len(inactive) != 1 {
		t.Errorf("Expected 1 inactive sandbox, got %d", len(inactive))
	} else if inactive[0].SessionID != "inactive-session" {
		t.Errorf("Expected inactive-session, got %s", inactive[0].SessionID)
	}
}

